package br.com.pueria.pueria.relatorios;

import br.com.pueria.pueria.crescimento.aplicacao.ListarAvaliacoesCurvaCrescimentoUseCase;
import br.com.pueria.pueria.crescimento.dominio.MedidaCrescimentoRepositorio;
import br.com.pueria.pueria.criancas.dominio.Crianca;
import br.com.pueria.pueria.criancas.dominio.CriancaRepositorio;
import br.com.pueria.pueria.desenvolvimento.aplicacao.GerenciarEstimulosDesenvolvimentoUseCase;
import br.com.pueria.pueria.desenvolvimento.aplicacao.ListarMarcosDesenvolvimentoUseCase;
import br.com.pueria.pueria.desenvolvimento.aplicacao.GerenciarRelatosDesenvolvimentoUseCase;
import br.com.pueria.pueria.responsaveis.dominio.VinculoResponsavelCriancaRepositorio;
import br.com.pueria.pueria.usuarios.dominio.UsuarioRepositorio;
import net.sf.jasperreports.engine.*;
import org.springframework.core.io.ClassPathResource;
import org.springframework.stereotype.Service;
import java.io.InputStream;
import java.time.LocalDate;
import java.time.format.DateTimeFormatter;
import java.util.*;

@Service public class ResumoConsultaPdfService {
 private final CriancaRepositorio criancas; private final UsuarioRepositorio usuarios; private final VinculoResponsavelCriancaRepositorio vinculos; private final ListarMarcosDesenvolvimentoUseCase marcos; private final GerenciarRelatosDesenvolvimentoUseCase relatos; private final GerenciarEstimulosDesenvolvimentoUseCase estimulos; private final ListarAvaliacoesCurvaCrescimentoUseCase crescimento; private final MedidaCrescimentoRepositorio medidas;
 public ResumoConsultaPdfService(CriancaRepositorio criancas,UsuarioRepositorio usuarios,VinculoResponsavelCriancaRepositorio vinculos,ListarMarcosDesenvolvimentoUseCase marcos,GerenciarRelatosDesenvolvimentoUseCase relatos,GerenciarEstimulosDesenvolvimentoUseCase estimulos,ListarAvaliacoesCurvaCrescimentoUseCase crescimento,MedidaCrescimentoRepositorio medidas){this.criancas=criancas;this.usuarios=usuarios;this.vinculos=vinculos;this.marcos=marcos;this.relatos=relatos;this.estimulos=estimulos;this.crescimento=crescimento;this.medidas=medidas;}
 public byte[] gerar(UUID criancaId,String email){ Crianca c=validar(criancaId,email); StringBuilder t=new StringBuilder(); t.append("GERADO EM ").append(LocalDate.now().format(DateTimeFormatter.ofPattern("dd/MM/yyyy"))).append("\n\n"); t.append("IDENTIFICAÇÃO\n").append(c.getNome()).append(" | Nascimento: ").append(c.getDataNascimento().format(DateTimeFormatter.ofPattern("dd/MM/yyyy"))).append(" | Sexo: ").append(c.getSexo()).append("\n"); if(c.isPrematura())t.append("Prematuridade: ").append(c.getSemanasGestacionais()).append(" semanas e ").append(c.getDiasGestacionais()).append(" dias.\n"); t.append("\nCRESCIMENTO — TRAJETÓRIA RECENTE\n"); var avaliacoes=crescimento.executar(criancaId,email); var porId=avaliacoes.stream().collect(java.util.stream.Collectors.toMap(a->a.medidaId(),a->a)); medidas.listarPorCrianca(criancaId).stream().sorted(java.util.Comparator.comparing(m->m.getDataMedicao(),java.util.Comparator.reverseOrder())).limit(3).forEach(m->{t.append("• ").append(m.getDataMedicao().format(DateTimeFormatter.ofPattern("dd/MM/yyyy"))).append(": "); if(m.getPesoKg()!=null)t.append("peso ").append(m.getPesoKg()).append(" kg; "); if(m.getComprimentoCm()!=null)t.append("comprimento ").append(m.getComprimentoCm()).append(" cm; "); if(m.getPerimetroCefalicoCm()!=null)t.append("PC ").append(m.getPerimetroCefalicoCm()).append(" cm; "); t.append("origem ").append(m.getOrigem().name().replace('_',' ')).append(".\n"); var a=porId.get(m.getId()); if(a!=null){t.append("  Referência: ").append(a.criterioIdade()).append(a.idadeCorrigida()?" | idade corrigida usada.\n":".\n");a.resultados().forEach(r->t.append("  - ").append(r.indicador().name().replace('_',' ')).append(": P").append(Math.round(r.percentil())).append(" | Z ").append(String.format(java.util.Locale.US,"%.2f",r.zScore())).append(" | ").append(r.classificacao().name().replace('_',' ')).append("\n"));}}); t.append("\nDESENVOLVIMENTO — PONTOS PARA CONVERSAR\n"); marcos.executar(criancaId,email).stream().filter(m->m.status().name().equals("AINDA_NAO_OBSERVADO")||m.status().name().equals("NAO_TENHO_CERTEZA")).forEach(m->t.append("• ").append(m.idadeMeses()).append(" meses | ").append(m.area().name().replace('_',' ')).append(": ").append(m.descricao()).append(" — ").append(m.status().name().equals("NAO_TENHO_CERTEZA")?"Às vezes":"Ainda não").append("\n")); t.append("\nCONTEXTO DA FAMÍLIA\n"); relatos.listar(criancaId,email).forEach(r->t.append("• ").append(r.getTipo().name().replace('_',' ')).append(": ").append(r.getDescricao()).append("\n")); t.append("\nATIVIDADES EXPERIMENTADAS\n"); estimulos.listarHistorico(criancaId,email).forEach(e->t.append("• ").append(e.titulo()).append(e.observacao()==null?"":" — "+e.observacao()).append("\n")); t.append("\nEste relatório organiza informações registradas pela família e pelo acompanhamento. Não estabelece diagnóstico e não substitui avaliação pediátrica."); try(InputStream in=new ClassPathResource("relatorios/resumo-consulta.jrxml").getInputStream()){JasperReport r=JasperCompileManager.compileReport(in); return JasperExportManager.exportReportToPdf(JasperFillManager.fillReport(r,new java.util.HashMap<>(Map.of("CONTEUDO",t.toString())),new JREmptyDataSource()));}catch(Exception e){throw new IllegalStateException("Não foi possível gerar o relatório para consulta.",e);} }
 private Crianca validar(UUID id,String email){var u=usuarios.buscarPorEmail(email).orElseThrow();if(!vinculos.usuarioPodeAcessarCrianca(u.getId(),id))throw new IllegalArgumentException("Criança não encontrada.");return criancas.buscarPorId(id).orElseThrow();}
}
